select id as rowId,expert_list as expertList,ethic_expert_list as ethicExpertList from srm_project_solicit_audit
where is_cancel=0

    and sys_no=#{projectSolicitAuditDto.sysNo}


    and soli_project_id=#{projectSolicitAuditDto.ywRowId}


    and type=#{projectSolicitAuditDto.type}


    and allot_count=#{projectSolicitAuditDto.allotCount}

select id from srm_project_solicit_audit 
where 1=1

    and sys_no=#{projectSolicitAuditDto.sysNo}


    and soli_project_id=#{projectSolicitAuditDto.ywRowId}


    and type=#{projectSolicitAuditDto.type}


    and allot_count=#{projectSolicitAuditDto.allotCount}

mapper.update:
update srm_project_solicit_audit
set expert_list=#{expertList},
    ethic_expert_list=#{ethicExpertList}
where 1=1

   and sys_no=#{sysNo}


    and soli_project_id=#{ywRowId}


    and type=#{type}


    and allot_count=#{allotCount}
